<template><div class="mx-auto max-w-6xl"><section class="mb-6"><p class="text-sm font-semibold text-primary">OPERATIONS</p><h2 class="mt-1 text-2xl font-semibold">Tournament results</h2><p class="mt-2 text-sm text-slate-500">All registered entries start as Pending. Set placement when results are announced.</p></section><UCard><UFormField label="Tournament"><USelect v-model="tournamentId" :items="tournamentOptions" placeholder="Select tournament" class="max-w-xl" /></UFormField></UCard><UCard v-if="tournamentId" class="mt-6"><template #header><h3 class="font-semibold">Registered participants</h3></template><div class="overflow-x-auto"><table class="min-w-[1050px] text-sm"><thead class="border-b border-slate-100 text-left text-xs uppercase text-slate-400 dark:border-slate-800"><tr><th class="px-3 py-3">Student</th><th class="px-3 py-3">Event</th><th class="px-3 py-3">Belt division</th><th class="px-3 py-3">Result</th><th class="px-3 py-3">Place secured</th><th class="px-3 py-3">Medal</th><th></th></tr></thead><tbody><tr v-for="entry in entries" :key="entry.id" class="border-b border-slate-100 last:border-0 dark:border-slate-800"><td class="px-3 py-3 font-medium">{{ entry.student?.firstName }} {{ entry.student?.lastName }}</td><td class="px-3 py-3 capitalize">{{ entry.eventType }}</td><td class="px-3 py-3">{{ entry.beltDivision === 'brown_black' ? 'Brown / Black' : 'Colour' }}</td><td class="px-3 py-3"><UInput v-model="entry.result" placeholder="Pending" /></td><td class="px-3 py-3"><USelect v-model="entry.placeSecured" :items="placeOptions" /></td><td class="px-3 py-3"><UBadge :color="medalFor(entry.placeSecured) ? 'warning' : 'neutral'" variant="subtle">{{ medalFor(entry.placeSecured) || '—' }}</UBadge></td><td class="px-3 py-3"><UButton size="xs" :loading="savingId === entry.id" @click="save(entry)">Save</UButton></td></tr></tbody></table></div></UCard></div></template>
<script setup lang="ts">definePageMeta({ middleware: 'auth' }); const tournamentId = ref<number | null>(null); const entries = ref<any[]>([]); const savingId = ref<number | null>(null); const savingAll = ref(false); const toast = useToast(); const { data: tournaments } = await useFetch<any[]>('/api/tournaments'); const tournamentOptions = computed(() => (tournaments.value || []).map(t => ({ label: `${t.name} — ${t.level}`, value: t.id }))); const placeOptions = [{ label: 'Pending', value: null }, { label: '1st place', value: 1 }, { label: '2nd place', value: 2 }, { label: '3rd place', value: 3 }, { label: '4th place', value: 4 }]; watch(tournamentId, async id => { entries.value = id ? await $fetch(`/api/tournaments/${id}/entries`) : [] }); function medalFor(place: number | null) { return place === 1 ? 'Gold' : place === 2 ? 'Silver' : place === 3 || place === 4 ? 'Bronze' : '' } async function save(entry: any, silent = false) { if (!tournamentId.value) return; savingId.value = entry.id; try { await $fetch(`/api/tournaments/${tournamentId.value}/entries/${entry.id}`, { method: 'PATCH', body: { eventType: entry.eventType, beltDivision: entry.beltDivision || 'colour', ageCategory: entry.ageCategory || null, weightCategory: entry.weightCategory || null, result: entry.result || null, placeSecured: entry.placeSecured || null } }); if (!silent) toast.add({ color: 'success', title: 'Result saved' }) } finally { savingId.value = null } } async function saveAll() { savingAll.value = true; try { await Promise.all(entries.value.map(entry => save(entry, true))); toast.add({ color: 'success', title: 'All tournament results saved' }) } finally { savingAll.value = false } }</script>
<style scoped>
table th:first-child { position: sticky; left: 0; z-index: 2; background: rgb(15 23 42); }
table td:first-child { position: sticky; left: 0; z-index: 1; background: rgb(15 23 42); box-shadow: 2px 0 4px -3px rgba(0,0,0,.7); }
</style>
